const { requests, total } = $input.first().json;
// Sort by votes descending for context
const sorted = [...requests].sort((a, b) => b.votes - a.votes);
const reqText = sorted.map(r =>
  `  [${r.id}] "${r.title}" | Segment: ${r.segment} | Votes: ${r.votes} | Source: ${r.source}`
).join('\n');
const system = `You are a senior PM helping prioritise feature requests. You look beyond raw vote counts to understand strategic value, segment fit, and theme clustering. Return ONLY valid JSON.`;
const user = `Prioritise these ${total} feature requests. Our ICP is mid-market B2B SaaS companies. Enterprise requests are strategically important. SMB requests with high vote counts may indicate broad user need.

${reqText}

Return JSON:
{
  "clusters": [
    { "cluster_name": "string", "request_ids": ["string"], "theme": "string", "total_votes": 0, "primary_segment": "string" }
  ],
  "top_10_ranked": [
    { "rank": 1, "id": "string", "title": "string", "rationale": "string", "estimated_impact": "high|medium|low", "strategic_fit": "core|adjacent|opportunistic" }
  ],
  "quick_wins": ["string — ID: reason why quick win"],
  "defer": ["string — ID: reason to defer"],
  "confidence": "low|medium|high"
}`;
return [{ json: { requests, total, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Prioritisation Prompt').first().json;
let parsed;
try {
  const c = response.choices?.[0]?.message?.content;
  if (!c) throw new Error('No content');
  parsed = JSON.parse(c);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.top_10_ranked || !Array.isArray(parsed.top_10_ranked)) return [{ json: { _error: true, reason: 'Missing top_10_ranked' } }];
return [{ json: { _error: false, prioritisation: parsed, meta: { total: upstream.total, generated_at: new Date().toISOString() } } }];

const { prioritisation: p, meta: m } = $input.first().json;
const clusterLines = (p.clusters||[]).map(c => `  ${c.cluster_name} (${c.total_votes} votes, ${c.request_ids.length} requests): ${c.theme}`).join('\n');
const top10Lines = (p.top_10_ranked||[]).map(r => `  #${r.rank} [${r.id}] ${r.title}\n    Impact: ${r.estimated_impact} | Fit: ${r.strategic_fit}\n    Rationale: ${r.rationale}`).join('\n');
const report = [
  `FEATURE REQUEST PRIORITISATION`,
  `Generated: ${m.generated_at} | Requests analysed: ${m.total}`,
  ``,
  `THEME CLUSTERS:`,
  clusterLines,
  ``,
  `TOP 10 PRIORITISED:`,
  top10Lines,
  ``,
  `QUICK WINS:`,
  (p.quick_wins||[]).map(q => `  → ${q}`).join('\n'),
  ``,
  `DEFER:`,
  (p.defer||[]).map(d => `  ✗ ${d}`).join('\n'),
].join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
